    i = 0
    while i < len(xs):
        # Check if current element is the maximum so far (including itself)
        max_so_far = xs[i]
        for j in range(i + 1, len(xs)):
            if xs[j] > max_so_far:
                max_so_far = xs[j]

        # If current element is not the maximum, skip it
        if xs[i] == max_so_far:
            result.append(xs[i])
        i += 1

    # Remove duplicates while preserving order
    seen = set()
    unique_result = []
    for x in result:
        if x not in seen:
            seen.add(x)
            unique_result.append(x)

    return unique_result

